<section class="page-heading"><div><p class="eyebrow">Visão consolidada</p><h1>Dashboard executivo</h1><p>Métricas calculadas no servidor conforme o recorte selecionado.</p></div></section>
<form method="get" action="/dashboard" class="filters" aria-label="Filtros do dashboard"><label>Ano<input type="number" name="ano" value="<?=e(isset($filters['ano'])?$filters['ano']:'')?>"></label><label>Mês<select name="mes"><option value="">Todos</option><?php for($m=1;$m<=12;$m++):?><option value="<?=$m?>" <?=isset($filters['mes'])&&(int)$filters['mes']===$m?'selected':''?>><?=$m?></option><?php endfor;?></select></label><label>Plano<input name="plano" value="<?=e(isset($filters['plano'])?$filters['plano']:'')?>"></label><label>Pilar<input name="pilar" value="<?=e(isset($filters['pilar'])?$filters['pilar']:'')?>"></label><label>Unidade<input name="unidade" value="<?=e(isset($filters['unidade_apuradora'])?$filters['unidade_apuradora']:'')?>"></label><label>Diretoria<input name="diretoria" value="<?=e(isset($filters['diretoria_responsavel'])?$filters['diretoria_responsavel']:'')?>"></label><label>Status<input name="status" value="<?=e(isset($filters['status'])?$filters['status']:'')?>"></label><button>Aplicar</button><a href="/dashboard">Limpar</a></form>
<?php if(!$data['cards']['totalIndicadores']):?><div class="panel empty-state" role="status">Nenhum dado encontrado para os filtros selecionados.</div><?php endif;?>
<section class="dashboard-cards" aria-label="Resumo"><?php foreach(array('totalIndicadores'=>'Indicadores','indicadoresAtivos'=>'Ativos','indicadoresInativos'=>'Inativos','rascunhos'=>'Rascunhos','submetidos'=>'Submetidos','homologacoesPendentes'=>'Homologações pendentes','homologacoesAprovadas'=>'Aprovadas','homologacoesRejeitadas'=>'Rejeitadas','mediaAtingimento'=>'Média de atingimento')as$key=>$label):?><article class="panel"><span><?=e($label)?></span><strong><?=e($data['cards'][$key]===null?'Sem dados':$data['cards'][$key].($key==='mediaAtingimento'?'%':''))?></strong></article><?php endforeach;?></section>
<section class="panel"><h2>Distribuição por situação</h2><div class="accessible-bars"><?php $max=max(1,array_sum($data['graficos']['situacoes']));foreach($data['graficos']['situacoes']as$label=>$value):?><div><span><?=e($label)?>: <?=e($value)?></span><div class="bar-track" role="img" aria-label="<?=e($label.': '.$value)?>"><span style="width:<?=e(round($value/$max*100,2))?>%"></span></div></div><?php endforeach;?></div></section>
<section class="panel"><h2>Indicadores por pilar</h2><div class="table-wrap"><table><thead><tr><th>Pilar</th><th>Total</th><th>Atingidos</th><th>Abaixo da meta</th><th>Sem dados</th></tr></thead><tbody><?php foreach($data['graficos']['pilares']as$p):?><tr><td><?=e($p['pilar'])?></td><td><?=e($p['total'])?></td><td><?=e($p['atingidos'])?></td><td><?=e($p['abaixoMeta'])?></td><td><?=e($p['semDados'])?></td></tr><?php endforeach;?></tbody></table></div></section>
<section class="panel"><h2>Evolução mensal</h2><div class="table-wrap"><table><thead><tr><th>Competência</th><th>Lançamentos</th><th>Média de atingimento</th></tr></thead><tbody><?php foreach($data['graficos']['evolucao']as$x):?><tr><td><?=e($x['competencia'])?></td><td><?=e($x['lancamentos'])?></td><td><?=e($x['mediaAtingimento']===null?'Sem dados':$x['mediaAtingimento'].'%')?></td></tr><?php endforeach;?></tbody></table></div></section>
<section class="panel"><h2>Atualizações recentes</h2><div class="table-wrap"><table><thead><tr><th>Competência</th><th>Indicador</th><th>Status</th><th>Atualização</th></tr></thead><tbody><?php foreach($data['atualizacoesRecentes']as$x):?><tr><td><?=e($x['competencia'])?></td><td><?=e($x['indicador_id'])?></td><td><?=e($x['status'])?></td><td><?=e($x['updated_at'])?></td></tr><?php endforeach;?></tbody></table></div></section>
